import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract(data):
    result = {}
    for proj in data.get('projects', []):
        name = proj['path'].split('/')[-1]
        for fw in proj.get('frameworks', []):
            tfm = fw['framework']
            for pkg in fw.get('topLevelPackages', []):
                key = (name, tfm, pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(after)

all_keys = sorted(set(b.keys()) | set(a.keys()))
changes = []
unchanged = []
for k in all_keys:
    bv = b.get(k)
    av = a.get(k)
    if bv != av:
        changes.append((k, bv, av))
    else:
        unchanged.append((k, bv))

print('=== CHANGES ===')
if changes:
    for (proj,tfm,pkg), bv, av in changes:
        status = 'Added' if not bv else 'Removed' if not av else 'Aligned to highest'
        print(f'{proj:20s} {tfm:12s} {pkg:50s} {str(bv):>10s} -> {str(av):>10s}  ({status})')
else:
    print('None')

print()
print('=== UNCHANGED ===')
for (proj,tfm,pkg), v in unchanged:
    print(f'{proj:20s} {tfm:12s} {pkg:50s} {v}')
"

